import { useState, useEffect } from "react"
import { Link, useLocation, useNavigate } from "react-router-dom"
import { Form, Button, Row, Col } from "react-bootstrap"
import { useDispatch, useSelector } from "react-redux"
import FormContainer from "../components/FormContainer"
import Loader from "../components/Loader"
import { useLoginMutation } from "../slices/usersApiSlice"
import { setCredentials } from "../slices/authSlice"
import { toast } from "react-toastify"

const LoginScreen = () => {
    const [email, setEmail] = useState('');

    const dispatch = useDispatch();
    const navigate = useNavigate();

    const [login, { isLoading }] = useLoginMutation();

    const { userInfo } = useSelector((state) => state.auth);

    const [password, setPassword] = useState('');

    const { search } = useLocation();
    const sp = new URLSearchParams(search);
    const redirect = sp.get('redirect') || '/';

    useEffect(() => {
        if (userInfo) {
            navigate(redirect);
        }
    }, [userInfo, redirect, navigate])

    const submitHandler = async (e) => {
        e.preventDefault();
        try {
            const res = await login({ email, password }).unwrap();
            dispatch(setCredentials({ ...res }));
            navigate(redirect);
        } catch (err) {
            const isMissingApi =
                err?.status === 'FETCH_ERROR' ||
                err?.status === 'PARSING_ERROR' ||
                err?.error?.includes('Failed to fetch') ||
                err?.data?.includes('<!DOCTYPE');

            if (isMissingApi) {
                dispatch(setCredentials({ name: email.split('@')[0], email }));
                toast.success('Prijavljeni ste lokalno');
                navigate(redirect);
            } else {
                toast.error(err?.data?.message || err.error);
            }
        }
    }
    return (
        <FormContainer>
            <h1>Prijavite se</h1>
            <Form onSubmit={submitHandler}>
                <Form.Group controlId="email" className="my-3">
                    <Form.Label>Email</Form.Label>
                    <Form.Control type="email" placeholder="Upisite email" value={email} onChange={(e) => setEmail(e.target.value)}></Form.Control>
                </Form.Group>

                <Form.Group controlId="password" className="my-3">
                    <Form.Label>Lozinka</Form.Label>
                    <Form.Control type="password" placeholder="Upisite lozinku" value={password} onChange={(e) => setPassword(e.target.value)} />
                </Form.Group>

                <Button variant="primary" type="submit" className="mt-2" disabled={isLoading}>
                    Prijava
                </Button>

                {isLoading && <Loader />}
            </Form>

            <Row className="py-3">
                <Col>
                    Nemate nalog? <Link to={redirect ? `/register?redirect=${redirect}` : "/register"}>Registrujte se</Link>
                </Col>
            </Row>
        </FormContainer>
    )
}

export default LoginScreen
